package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.ir;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotSame;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Bound;
import org.eclipse.rdf4j.query.algebra.Compare;
import org.eclipse.rdf4j.query.algebra.Extension;
import org.eclipse.rdf4j.query.algebra.ExtensionElem;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.IRIFunction;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.ListMemberOperator;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Union;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.helpers.TupleExprs;
import org.junit.jupiter.api.Test;

class TupleExprIrRoundTripTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void roundTripProducesFreshTupleTreeWithSameOperatorShape() {
		Join input = new Join(pattern("drug", "p1", "target"), pattern("target", "p2", "pathway"));
		Filter filter = new Filter(input,
				new Compare(new Var("drug"), new ValueConstant(VF.createIRI("urn:drug:1")), Compare.CompareOp.EQ));

		PlanIr ir = TupleExprToIr.convert(filter);
		TupleExpr rendered = IrToTupleExpr.convert(ir);

		assertNotSame(filter, rendered);
		assertTrue(rendered instanceof Filter);
		assertTrue(((Filter) rendered).getArg() instanceof Join);
	}

	@Test
	void roundTripPreservesFilterScopeChangeFlag() {
		Filter filter = new Filter(pattern("drug", "p", "label"), new Bound(new Var("drug")));
		filter.setVariableScopeChange(true);

		TupleExpr rendered = IrToTupleExpr.convert(TupleExprToIr.convert(filter));

		assertTrue(((Filter) rendered).isVariableScopeChange());
	}

	@Test
	void roundTripPreservesUnionScopeChangeFlag() {
		Union union = new Union(pattern("s", "p1", "o"), pattern("s", "p2", "x"));
		union.setVariableScopeChange(true);

		TupleExpr rendered = IrToTupleExpr.convert(TupleExprToIr.convert(union));

		assertTrue(((Union) rendered).isVariableScopeChange());
	}

	@Test
	void roundTripPreservesExtensionScopeChangeFlag() {
		Extension extension = new Extension(pattern("drug", "p", "label"));
		extension.addElement(new ExtensionElem(new Var("label"), "alias"));
		extension.setVariableScopeChange(true);

		TupleExpr rendered = IrToTupleExpr.convert(TupleExprToIr.convert(extension));

		assertTrue(((Extension) rendered).isVariableScopeChange());
	}

	@Test
	void roundTripDoesNotInventScopeChangeFlags() {
		Filter filter = new Filter(pattern("drug", "p", "label"), new Bound(new Var("drug")));

		TupleExpr rendered = IrToTupleExpr.convert(TupleExprToIr.convert(filter));

		assertFalse(((Filter) rendered).isVariableScopeChange());
	}

	@Test
	void roundTripPreservesStatementPatternConstantFlag() {
		StatementPattern pattern = new StatementPattern(TupleExprs.createConstVar(VF.createIRI("urn:subject")),
				new Var("predicate"), new Var("object"));

		TupleExpr rendered = IrToTupleExpr.convert(TupleExprToIr.convert(pattern));

		assertTrue(((StatementPattern) rendered).getSubjectVar().isConstant());
		assertFalse(((StatementPattern) rendered).getPredicateVar().isConstant());
	}

	@Test
	void roundTripPreservesValueExprsTheIrCannotRepresent() {
		// IRIFunction has no ScalarExpr form. The IR must round-trip it losslessly instead of degrading it to a
		// placeholder function call with a urn:rdf4j:native: URI and dropped arguments, which evaluates to
		// "Unknown function" and loses the argument semantics (W3C bind error tests, SES-2250).
		Extension extension = new Extension(pattern("s", "p", "o"),
				new ExtensionElem(new IRIFunction(new Var("o")), "iri"));

		TupleExpr rendered = IrToTupleExpr.convert(TupleExprToIr.convert(extension));

		ExtensionElem renderedElem = ((Extension) rendered).getElements().get(0);
		assertTrue(renderedElem.getExpr() instanceof IRIFunction,
				() -> "The IR round-trip must preserve value expressions it cannot represent, but produced: "
						+ renderedElem.getExpr());
		assertNotSame(extension.getElements().get(0).getExpr(), renderedElem.getExpr(),
				"The rendered tree must not alias the input tree's expression nodes");
	}

	@Test
	void roundTripPreservesListMemberOperator() {
		ListMemberOperator in = new ListMemberOperator();
		in.addArgument(new Var("o"));
		in.addArgument(new ValueConstant(VF.createLiteral("a")));
		in.addArgument(new ValueConstant(VF.createLiteral("b")));
		Filter filter = new Filter(pattern("s", "p", "o"), in);

		TupleExpr rendered = IrToTupleExpr.convert(TupleExprToIr.convert(filter));

		assertTrue(((Filter) rendered).getCondition() instanceof ListMemberOperator,
				() -> "IN(...) must survive the IR round-trip with its arguments, but produced: "
						+ ((Filter) rendered).getCondition());
	}

	@Test
	void roundTripPreservesStatementPatternPlannedMetrics() {
		// Pre-planning contracts (e.g. the LMDB distinct-cursor-skip requirement) travel as planned metrics on
		// StatementPattern nodes. Compiled DSL rules round-trip matched subtrees through the IR, so a lossy
		// round-trip silently severs those contracts and the physical alternatives that depend on them.
		StatementPattern pattern = pattern("s", "p", "o");
		pattern.setStringMetricPlanned("optimizer.distinctRequirementVars", "p");
		pattern.setDoubleMetricPlanned("optimizer.plannedContractDouble", 4.0d);
		pattern.setLongMetricPlanned("optimizer.plannedContractLong", 7L);

		TupleExpr rendered = IrToTupleExpr.convert(TupleExprToIr.convert(pattern));

		StatementPattern renderedPattern = (StatementPattern) rendered;
		assertEquals("p", renderedPattern.getStringMetricPlanned("optimizer.distinctRequirementVars"),
				"planned string metrics on a StatementPattern must survive the IR round-trip");
		assertEquals(4.0d, renderedPattern.getDoubleMetricsPlanned().get("optimizer.plannedContractDouble"),
				"planned double metrics on a StatementPattern must survive the IR round-trip");
		assertEquals(7L, renderedPattern.getLongMetricsPlanned().get("optimizer.plannedContractLong"),
				"planned long metrics on a StatementPattern must survive the IR round-trip");
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}
}
